    type beatmapStatus = 'Graveyard'
        | 'WIP'
        | 'Pending'
        | 'Ranked'
        | 'Approved'
        | 'Qualified'
        | 'Loved';

    type userPP = {
        rank: number,
        /**
         * User's total pp.
         */
        raw: number,
        countryRank: number
    }

    type userScore = {
        total: number,
        ranked: number
    }

    type userCount = {
        /**
         * Total amount for all ranked, approved, and loved beatmaps played.
         */
        '300': number,
        /**
         * Total amount for all ranked, approved, and loved beatmaps played.
         */
        '100': number,
        /**
         * Total amount for all ranked, approved, and loved beatmaps played.
         */
        '50': number,
        /**
         * Only counts ranked, approved, and loved beatmaps.
         */
        play: number,
        /**
         * Total amount for all ranked, approved, and loved beatmaps played.
         */
        SS: number,
        /**
         * Total amount for all ranked, approved, and loved beatmaps played.
         */
        S: number,
        /**
         * Total amount for all ranked, approved, and loved beatmaps played.
         */
        A: number
    };

